# ---------------------------------------- CLASES DEL MOTOR LÉXICO ----------------------------------------

class LexicalError(Exception):
    """Excepción para errores léxicos con información de posición."""
    def __init__(self, message, line, col, char):
        self.line = line
        self.col = col
        self.char = char
        super().__init__(message)


class Token:
    """Representa un token reconocido con su tipo, lexema y posición."""
    def __init__(self, kind: str, value: str = "", line: int = 0, col: int = 0):
        self.kind = kind
        self.value = value
        self.line = line
        self.col = col

    def __repr__(self):
        if self.value and self.value != self.kind:
            return f"{self.kind}({self.value!r})"
        return f"{self.kind}"


# ---------------------------------------- DESPACHADOR DE ACCIONES ----------------------------------------

def _execute_action(rule_index: int, lxm: str, lexbuf_callback) -> str | None:
    """Ejecuta la acción de una regla. Retorna nombre del token o None para skip."""
    if rule_index == 0:  # [' ' '\t' '\n' '\r'] — skip
        return None

    if rule_index == 1:  # line_cmt — skip
        return None

    if rule_index == 2:  # float_lit
        return "FLOAT_LIT"

    if rule_index == 3:  # int_lit
        return "INT_LIT"

    if rule_index == 4:  # string_lit
        return "STRING_LIT"

    if rule_index == 5:  # "true"
        return "BOOL_LIT"

    if rule_index == 6:  # "false"
        return "BOOL_LIT"

    if rule_index == 7:  # "macro"
        return "KW_MACRO"

    if rule_index == 8:  # "emit"
        return "KW_EMIT"

    if rule_index == 9:  # "when"
        return "KW_WHEN"

    if rule_index == 10:  # "otherwise"
        return "KW_OTHERWISE"

    if rule_index == 11:  # "repeat"
        return "KW_REPEAT"

    if rule_index == 12:  # "until"
        return "KW_UNTIL"

    if rule_index == 13:  # "let"
        return "KW_LET"

    if rule_index == 14:  # ident
        return "IDENT"

    if rule_index == 15:  # "<-"
        return "ASSIGN"

    if rule_index == 16:  # "=="
        return "EQ"

    if rule_index == 17:  # "!="
        return "NEQ"

    if rule_index == 18:  # "<="
        return "LEQ"

    if rule_index == 19:  # ">="
        return "GEQ"

    if rule_index == 20:  # "&&"
        return "AND"

    if rule_index == 21:  # "||"
        return "OR"

    if rule_index == 22:  # '+'
        return "PLUS"

    if rule_index == 23:  # '-'
        return "MINUS"

    if rule_index == 24:  # '*'
        return "TIMES"

    if rule_index == 25:  # '/'
        return "DIV"

    if rule_index == 26:  # '%'
        return "MOD"

    if rule_index == 27:  # '<'
        return "LT"

    if rule_index == 28:  # '>'
        return "GT"

    if rule_index == 29:  # '!'
        return "NOT"

    if rule_index == 30:  # '('
        return "LPAREN"

    if rule_index == 31:  # ')'
        return "RPAREN"

    if rule_index == 32:  # '{'
        return "LBRACE"

    if rule_index == 33:  # '}'
        return "RBRACE"

    if rule_index == 34:  # ';'
        return "SEMICOLON"

    if rule_index == 35:  # ','
        return "COMMA"

    if rule_index == 36:  # eof — EOF
        return "__EOF__"

    return None


# ---------------------------------------- MOTOR DE ANÁLISIS LÉXICO ----------------------------------------

def gettoken(text: str) -> list[Token]:
    """
    Simula el AFD sobre el texto de entrada. Aplica la regla de longest match:
    siempre consume el prefijo más largo que concuerda con algún patrón.
    """
    tokens = []
    pos = 0
    line = 1
    col = 1
    length = len(text)

    while pos < length:
        # Iniciar simulación del AFD desde el estado inicial
        current_state = _START_STATE
        last_accept_pos = -1
        last_accept_rule = -1
        scan_pos = pos
        scan_line = line
        scan_col = col

        # Avanzar mientras existan transiciones válidas
        while scan_pos < length:
            ch = ord(text[scan_pos])
            trans = _TRANSITION_TABLE.get(current_state, {})
            if ch in trans:
                current_state = trans[ch]
                scan_pos += 1
                if ch == ord('\n'):
                    scan_line += 1
                    scan_col = 1
                else:
                    scan_col += 1
                # Recordar la última posición de aceptación
                if current_state in _ACCEPT_STATES:
                    last_accept_pos = scan_pos
                    last_accept_rule = _ACCEPT_STATES[current_state]
            else:
                break

        # Verificar aceptación al final del input
        if scan_pos == length and current_state in _ACCEPT_STATES:
            if scan_pos > last_accept_pos:
                last_accept_pos = scan_pos
                last_accept_rule = _ACCEPT_STATES[current_state]

        if last_accept_pos > pos:
            lexeme = text[pos:last_accept_pos]
            token_name = _execute_action(last_accept_rule, lexeme, None)
            if token_name is not None:
                if token_name == "__EOF__":
                    break
                tokens.append(Token(token_name, lexeme, line, col))
            # Actualizar posición
            for ch in lexeme:
                if ch == '\n':
                    line += 1
                    col = 1
                else:
                    col += 1
            pos = last_accept_pos
        else:
            bad_char = text[pos]
            raise LexicalError(
                f"LEXICAL ERROR at line {line}: Unrecognized character {bad_char!r}",
                line, col, bad_char
            )

    return tokens


# ---------------------------------------- PROGRAMA PRINCIPAL ----------------------------------------

def main():
    if len(sys.argv) < 2:
        print("------------------------------------------------------------")
        print("  USO: python {sys.argv[0]} <archivo_fuente>")
        print("------------------------------------------------------------")
        sys.exit(1)

    filename = sys.argv[1]
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            source = f.read()
    except FileNotFoundError:
        print(f"  ERROR: No se encontró el archivo '{filename}'")
        sys.exit(1)

    try:
        tokens = gettoken(source)
        print("------------------------------------------------------------")
        print(f"  TOKENS RECONOCIDOS — {filename}")
        print("------------------------------------------------------------")
        for tok in tokens:
            print(f"  {tok}")
        print("------------------------------------------------------------")
        print(f"  Total: {len(tokens)} tokens")
        print("------------------------------------------------------------")
    except LexicalError as e:
        print(e)
        sys.exit(1)


if __name__ == "__main__":
    main()

